/* Node.js: simple server that signals overload with 503 when queue is full */
const http = require('http');
const queue = [];
const MAX_QUEUE = 100;

http.createServer((req, res) => {
  if (queue.length >= MAX_QUEUE) {
    res.writeHead(503, { 'Retry-After': '10', 'Content-Type': 'application/json' });
    return res.end(JSON.stringify({ error: 'server_overloaded', retry_after: 10 }));
  }

  // enqueue work and return 202 Accepted
  queue.push({ req });
  res.writeHead(202);
  res.end();
}).listen(8080);

// Worker loop drains queue at controlled rate
setInterval(() => {
  const item = queue.shift();
  if (!item) return;
  // process item
}, 100);
